const raw = $json.text || '';
const lines = raw.split('\n');

// Extract META description
let metaDescription = '';
let bodyStart = 0;
if (lines[0].startsWith('META:')) {
  metaDescription = lines[0].replace('META:', '').trim();
  bodyStart = lines[1] === '---' ? 2 : 1;
}

const body = lines.slice(bodyStart).join('\n').trim();
const keyword = $('Webhook Trigger').item.json.keyword;
const title = $('Webhook Trigger').item.json.recommended_title || `The Complete Guide to ${keyword}`;
const domain = $('Webhook Trigger').item.json.domain;
const keywordId = $('Webhook Trigger').item.json.Id;

// Ghost API key comes from env — set in n8n credentials or env
// Format: ghost_<site>_admin_api_key
const ghostKeyEnvMap = {
  'mostlyprompt.com': $env.GHOST_MOSTLYPROMPT_ADMIN_API_KEY,
  'fellowcoder.com': $env.GHOST_FELLOWCODER_ADMIN_API_KEY,
};
const ghostKey = ghostKeyEnvMap[domain] || '';

return [{
  json: {
    title,
    body,
    metaDescription,
    keyword,
    domain,
    keywordId,
    ghostKey,
    tags: [{ name: keyword }, { name: 'AI Generated' }]
  }
}];

